class MinStack {
    Stack<Integer> stack = new LinkedList<>();
    int minElement = Integer.MAX_VALUE;

    public MinStack() {
    }

    public void push(int val) {
        stack.push(val);
        if (val < minElement) {
            minElement = val;
        }
    }

    public void pop() {
        stack.pop();
        minElement = Math.max(minElement, stack.peek());
    }

    public int top() {
        return stack.peek();
    }

    public int getMin() {
        return minElement;
    }
}
```

